3	namespace App\Http\Middleware;
4	
5	use App\Models\ApiToken;
6	use Closure;
7	use Illuminate\Http\Request;
8	use Symfony\Component\HttpFoundation\Response;
9	
10	class AuthenticateToken
11	{
12	    public function handle(Request $request, Closure $next): Response
13	    {
14	        $bearerToken = $request->bearerToken();
15	
16	        if (!$bearerToken) {
17	            return response()->json([
18	                'error' => 'Unauthenticated',
19	                'message' => 'A valid API token is required.',
20	            ], 401);
21	        }
22	
23	        $hashedToken = hash('sha256', $bearerToken);
24	        $apiToken = ApiToken::where('token', $hashedToken)
25	            ->where('is_revoked', false)
26	            ->first();
27	
28	        if (!$apiToken || !$apiToken->isValid()) {
29	            return response()->json([
30	                'error' => 'Unauthenticated',
31	                'message' => 'Invalid or expired token.',
32	            ], 401);
33	        }
34	
35	        $user = $apiToken->user;
36	
37	        if (!$user || !$user->is_active) {
38	            return response()->json([
39	                'error' => 'Unauthenticated',
40	                'message' => 'User account is inactive.',
41	            ], 401);
42	        }
43	
44	        $apiToken->update(['last_used_at' => now()]);
45	
46	        $request->merge(['api_token' => $apiToken]);
47	        $request->setUserResolver(fn () => $user);
48	
49	        return $next($request);
50	    }
51	}
