9	
10	class LogRequestResponse
11	{
12	    /**
13	     * Sensitive fields that should not be logged.
14	     */
15	    private const REDACTED_FIELDS = [
16	        'password',
17	        'password_confirmation',
18	        'current_password',
19	        'token',
20	        'authorization',
21	        'email',
22	        'phone',
23	        'guardian_contact',
24	        'guardian_name',
25	        'address',
26	        'date_of_birth',
27	        'first_name',
28	        'last_name',
29	        'answers',
30	        'ssn',
31	        'national_id',
32	    ];
33	
34	    public function handle(Request $request, Closure $next): Response
35	    {
36	        $startTime = microtime(true);
37	
38	        $response = $next($request);
39	
40	        $duration = round((microtime(true) - $startTime) * 1000, 2);
41	
42	        $this->logRequest($request, $response, $duration);
43	
44	        return $response;
45	    }
46	
47	    private function logRequest(Request $request, Response $response, float $durationMs): void
48	    {
49	        $statusCode = $response->getStatusCode();
50	        $method = $request->method();
51	        $path = $request->path();
52	        $userId = $request->user()?->id;
53	
54	        $context = [
55	            'method' => $method,
56	            'path' => $path,
57	            'status' => $statusCode,
58	            'duration_ms' => $durationMs,
59	            'ip' => $request->ip(),
60	            'user_id' => $userId,
61	            'user_agent' => substr($request->userAgent() ?? '', 0, 200),
62	        ];
63	
64	        // Include sanitized request params for non-GET requests
65	        if (!$request->isMethod('GET')) {
66	            $context['params'] = $this->sanitizeParams($request->all());
67	        }
68	
69	        // Log level based on status code
70	        $message = "{$method} /{$path} → {$statusCode} ({$durationMs}ms)";
71	
72	        if ($statusCode >= 500) {
73	            Log::error($message, $context);
74	        } elseif ($statusCode >= 400) {
75	            Log::warning($message, $context);
76	        } else {
77	            Log::info($message, $context);
78	        }
79	    }
80	
81	    private function sanitizeParams(array $params): array
82	    {
83	        $sanitized = [];
84	
85	        foreach ($params as $key => $value) {
86	            if (in_array(strtolower($key), self::REDACTED_FIELDS)) {
87	                $sanitized[$key] = '[REDACTED]';
88	            } elseif (is_array($value)) {
89	                $sanitized[$key] = $this->sanitizeParams($value);
90	            } else {
91	                $sanitized[$key] = $value;
92	            }
93	        }
94	
95	        return $sanitized;
96	    }
97	}
