16	     * Create a new enrollment in draft status with workflow metadata.
17	     */
18	    public function createEnrollment(array $data, Learner $learner, int $approvalLevels = 1): Enrollment
19	    {
20	        $workflowMetadata = ApprovalWorkflow::buildDefault($learner, $approvalLevels);
21	
22	        $enrollment = Enrollment::create([
23	            'learner_id' => $learner->id,
24	            'program_name' => $data['program_name'],
25	            'status' => Enrollment::STATUS_DRAFT,
26	            'max_approval_levels' => $workflowMetadata['levels'],
27	            'workflow_metadata' => $workflowMetadata,
28	            'requires_guardian_approval' => $workflowMetadata['requires_guardian_approval'],
29	            'payment_amount' => $data['payment_amount'] ?? null,
30	            'refund_cutoff_at' => $data['refund_cutoff_at'] ?? null,
31	            'notes' => $data['notes'] ?? null,
32	            'last_actor_id' => $data['actor_id'] ?? null,
33	        ]);
34	
35	        return $enrollment;
36	    }
37	
38	    /**
39	     * Transition an enrollment to a new status with validation.
40	     */
41	    public function transition(Enrollment $enrollment, string $newStatus, User $actor, ?string $reasonCode = null, ?string $notes = null): Enrollment
42	    {
43	        if (!$enrollment->canTransitionTo($newStatus)) {
44	            throw new \InvalidArgumentException(
45	                "Cannot transition from '{$enrollment->status}' to '{$newStatus}'. " .
46	                'Allowed transitions: ' . implode(', ', $enrollment->getAllowedTransitions())
47	            );
48	        }
49	
50	        // Check workflow blockers for advancement transitions
51	        if (in_array($newStatus, [Enrollment::STATUS_UNDER_REVIEW, Enrollment::STATUS_APPROVED])) {
52	            $learner = $enrollment->learner;
53	            $check = ApprovalWorkflow::canAdvance($enrollment->workflow_metadata ?? [], $learner);
54	
55	            if (!$check['can_advance']) {
56	                throw new \InvalidArgumentException(
57	                    'Cannot advance enrollment: ' . implode('; ', $check['blockers'])
58	                );
59	            }
60	        }
61	
62	        return DB::transaction(function () use ($enrollment, $newStatus, $actor, $reasonCode, $notes) {
63	            $previousStatus = $enrollment->status;
64	
65	            $updateData = [
66	                'previous_status' => $previousStatus,
67	                'status' => $newStatus,
68	                'last_actor_id' => $actor->id,
69	                'reason_code' => $reasonCode ?? $enrollment->reason_code,
70	            ];
71	
72	            if ($notes) {
73	                $updateData['notes'] = $notes;
74	            }
75	
76	            // Set timestamps based on transition
77	            switch ($newStatus) {
78	                case Enrollment::STATUS_ENROLLED:
79	                    $updateData['enrolled_at'] = now();
80	                    break;
81	                case Enrollment::STATUS_COMPLETED:
82	                    $updateData['completed_at'] = now();
83	                    break;
84	                case Enrollment::STATUS_CANCELLED:
85	                    $updateData['cancelled_at'] = now();
86	                    break;
87	                case Enrollment::STATUS_REFUNDED:
88	                    $updateData['refunded_at'] = now();
89	                    break;
90	            }
91	
92	            $enrollment->update($updateData);
93	
94	            // Record immutable transition history
95	            EnrollmentTransition::create([
96	                'enrollment_id' => $enrollment->id,
97	                'from_status' => $previousStatus,
98	                'to_status' => $newStatus,
99	                'actor_id' => $actor->id,
100	                'reason_code' => $reasonCode,
101	                'notes' => $notes,
102	                'created_at' => now(),
103	            ]);
104	
105	            return $enrollment->fresh();
106	        });
107	    }
108	
109	    /**
110	     * Submit an enrollment for review (draft → submitted).
111	     */
112	    public function submitForReview(Enrollment $enrollment, User $actor): Enrollment
113	    {
114	        return $this->transition($enrollment, Enrollment::STATUS_SUBMITTED, $actor, 'submitted_for_review');
115	    }
116	
117	    /**
118	     * Begin review of an enrollment (submitted → under_review).
119	     * Creates the first approval record.
120	     */
121	    public function beginReview(Enrollment $enrollment, User $reviewer): Enrollment
122	    {
123	        $enrollment = $this->transition($enrollment, Enrollment::STATUS_UNDER_REVIEW, $reviewer, 'review_started');
124	
125	        // Create first-level approval record
126	        Approval::create([
127	            'enrollment_id' => $enrollment->id,
128	            'reviewer_id' => $reviewer->id,
129	            'level' => 1,
130	            'status' => 'in_review',
131	        ]);
132	
133	        $enrollment->update(['current_approval_level' => 1]);
134	
135	        return $enrollment->fresh();
136	    }
137	
138	    /**
139	     * Process an approval decision at the current level.
140	     */
141	    public function processApproval(Enrollment $enrollment, User $reviewer, string $decision, ?string $comments = null, ?string $reasonCode = null): Enrollment
142	    {
143	        if (!in_array($decision, ['approved', 'rejected'])) {
144	            throw new \InvalidArgumentException("Decision must be 'approved' or 'rejected'.");
145	        }
146	
147	        $currentLevel = $enrollment->current_approval_level;
148	
149	        // Find or create the approval for the current level
150	        $approval = Approval::where('enrollment_id', $enrollment->id)
151	            ->where('level', $currentLevel)
152	            ->first();
153	
154	        if (!$approval) {
155	            $approval = Approval::create([
156	                'enrollment_id' => $enrollment->id,
157	                'reviewer_id' => $reviewer->id,
158	                'level' => $currentLevel,
159	                'status' => 'in_review',
160	            ]);
161	        }
162	
163	        // Record the decision
164	        $approval->update([
165	            'reviewer_id' => $reviewer->id,
166	            'status' => $decision,
167	            'decision' => $decision,
168	            'comments' => $comments,
169	            'reason_code' => $reasonCode,
170	            'decided_at' => now(),
171	        ]);
172	
173	        if ($decision === 'rejected') {
174	            return $this->transition($enrollment, Enrollment::STATUS_REJECTED, $reviewer, $reasonCode ?? 'rejected', $comments);
175	        }
176	
177	        // Approved — check if more levels needed
178	        if ($currentLevel < $enrollment->max_approval_levels) {
179	            // Advance to next level
180	            $nextLevel = $currentLevel + 1;
181	            $enrollment->update(['current_approval_level' => $nextLevel]);
182	
183	            // Create next-level approval record
184	            Approval::create([
185	                'enrollment_id' => $enrollment->id,
186	                'level' => $nextLevel,
187	                'status' => 'pending',
188	            ]);
189	
190	            return $enrollment->fresh();
191	        }
192	
193	        // All levels approved
194	        return $this->transition($enrollment, Enrollment::STATUS_APPROVED, $reviewer, $reasonCode ?? 'fully_approved', $comments);
195	    }
