7	/**
8	 * Value object representing workflow configuration for an enrollment.
9	 * Stored as JSON in enrollments.workflow_metadata.
10	 */
11	class ApprovalWorkflow extends Model
12	{
13	    // This is not backed by a table — used as a structured helper.
14	    protected $guarded = [];
15	    public $exists = false;
16	
17	    /**
18	     * Build default workflow metadata for an enrollment.
19	     */
20	    public static function buildDefault(Learner $learner, int $levels = 1): array
21	    {
22	        $isMinor = $learner->isMinor();
23	        $hasGuardian = !empty($learner->guardian_contact);
24	
25	        // Minors require at least 2 levels and guardian approval
26	        if ($isMinor) {
27	            $levels = max($levels, 2);
28	        }
29	
30	        $levels = min($levels, 3);
31	
32	        $workflow = [
33	            'levels' => $levels,
34	            'requires_guardian_approval' => $isMinor,
35	            'guardian_contact_verified' => $isMinor && $hasGuardian,
36	            'conditions' => [],
37	            'level_config' => [],
38	        ];
39	
40	        // Add conditional branching rules
41	        if ($isMinor) {
42	            $workflow['conditions'][] = [
43	                'type' => 'minor_check',
44	                'field' => 'date_of_birth',
45	                'rule' => 'age_under_18',
46	                'action' => 'require_guardian_approval',
47	            ];
48	
49	            if (!$hasGuardian) {
50	                $workflow['conditions'][] = [
51	                    'type' => 'blocking',
52	                    'field' => 'guardian_contact',
53	                    'rule' => 'required_for_minor',
54	                    'action' => 'block_advancement',
55	                    'message' => 'Guardian contact required for minor learners.',
56	                ];
57	            }
58	        }
59	
60	        // Configure each approval level
61	        for ($i = 1; $i <= $levels; $i++) {
62	            $config = [
63	                'level' => $i,
64	                'required_role' => 'reviewer',
65	                'auto_assign' => false,
66	            ];
67	
68	            if ($i === 2 && $isMinor) {
69	                $config['required_role'] = 'admin';
70	                $config['description'] = 'Guardian approval verification for minor learner.';
71	            }
72	
73	            $workflow['level_config'][] = $config;
74	        }
75	
76	        return $workflow;
77	    }
78	
79	    /**
80	     * Check if a workflow allows advancement to the next approval level.
81	     */
82	    public static function canAdvance(array $workflowMetadata, Learner $learner): array
83	    {
84	        $blockers = [];
85	
86	        foreach ($workflowMetadata['conditions'] ?? [] as $condition) {
87	            if ($condition['type'] === 'blocking') {
88	                if ($condition['rule'] === 'required_for_minor' && $learner->isMinor()) {
89	                    if (empty($learner->guardian_contact)) {
90	                        $blockers[] = $condition['message'] ?? 'Condition not met: ' . $condition['field'];
91	                    }
92	                }
93	            }
94	        }
95	
96	        return [
97	            'can_advance' => empty($blockers),
98	            'blockers' => $blockers,
99	        ];
100	    }
