26	        ]);
27	
28	        $user = User::where('username', $request->username)->first();
29	
30	        if (!$user) {
31	            return response()->json([
32	                'error' => 'Unauthorized',
33	                'message' => 'Invalid credentials.',
34	            ], 401);
35	        }
36	
37	        if ($user->isLockedOut()) {
38	            return response()->json([
39	                'error' => 'Locked',
40	                'message' => 'Account is temporarily locked due to too many failed login attempts.',
41	                'locked_until' => $user->locked_until->toIso8601String(),
42	            ], 423);
43	        }
44	
45	        if (!$user->is_active) {
46	            return response()->json([
47	                'error' => 'Unauthorized',
48	                'message' => 'Account is inactive.',
49	            ], 401);
50	        }
51	
52	        if (!Hash::check($request->password, $user->password)) {
53	            $user->incrementFailedAttempts();
54	
55	            $response = [
56	                'error' => 'Unauthorized',
57	                'message' => 'Invalid credentials.',
58	            ];
59	
60	            if ($user->isLockedOut()) {
