62	                $response['locked_until'] = $user->locked_until->toIso8601String();
63	            }
64	
65	            return response()->json($response, 401);
66	        }
67	
68	        // Successful login
69	        $user->resetFailedAttempts();
70	        $user->update(['last_login_at' => now()]);
71	
72	        // Generate token
