3	namespace App\Services;
4	
5	use App\Models\Learner;
6	use App\Models\LearnerIdentifier;
7	
8	class DeduplicationService
9	{
10	    private DataNormalizationService $normalizer;
11	
12	    public function __construct(DataNormalizationService $normalizer)
13	    {
14	        $this->normalizer = $normalizer;
15	    }
16	
17	    /**
18	     * Generate a deterministic fingerprint for a learner based on core identity fields.
19	     * Uses normalized first_name + last_name + date_of_birth + last-4 phone digits.
20	     */
21	    public function generateFingerprint(array $data): string
22	    {
23	        $parts = [];
24	
25	        $firstName = $this->normalizer->normalizeName($data['first_name'] ?? '');
26	        $lastName = $this->normalizer->normalizeName($data['last_name'] ?? '');
27	        $dob = $this->normalizer->normalizeDate($data['date_of_birth'] ?? '');
28	        $phone = $this->normalizer->normalizePhone($data['phone'] ?? '');
29	        $phoneLast4 = $phone ? substr(preg_replace('/\D/', '', $phone), -4) : '';
30	
31	        $parts[] = mb_strtolower(trim($firstName ?? ''));
32	        $parts[] = mb_strtolower(trim($lastName ?? ''));
33	        $parts[] = $dob ?? '';
34	        $parts[] = $phoneLast4;
35	
36	        $raw = implode('|', $parts);
37	
38	        return hash('sha256', $raw);
39	    }
40	
41	    /**
42	     * Generate an identifier-level fingerprint for deduplication on specific fields.
43	     */
44	    public function generateIdentifierFingerprint(string $type, string $value): string
45	    {
46	        $normalizedValue = match ($type) {
47	            'email' => $this->normalizer->normalizeEmail($value),
48	            'phone' => $this->normalizer->normalizePhone($value),
49	            default => mb_strtolower(trim($value)),
50	        };
51	
52	        return hash('sha256', "{$type}|{$normalizedValue}");
53	    }
54	
55	    /**
56	     * Compute and store the learner fingerprint.
57	     */
58	    public function computeAndStoreFingerprint(Learner $learner): string
59	    {
60	        $fingerprint = $this->generateFingerprint($learner->toArray());
61	
62	        $learner->update(['fingerprint' => $fingerprint]);
63	
64	        return $fingerprint;
65	    }
66	
67	    /**
68	     * Register a learner identifier and check for duplicates.
69	     */
70	    public function registerIdentifier(Learner $learner, string $type, string $value, bool $isPrimary = false): LearnerIdentifier
71	    {
72	        $fingerprint = $this->generateIdentifierFingerprint($type, $value);
73	
74	        $identifier = LearnerIdentifier::create([
75	            'learner_id' => $learner->id,
76	            'type' => $type,
77	            'value' => $value,
78	            'fingerprint' => $fingerprint,
79	            'is_primary' => $isPrimary,
80	        ]);
81	
82	        // Check for existing identifiers with the same fingerprint belonging to other learners
83	        $duplicates = LearnerIdentifier::where('fingerprint', $fingerprint)
84	            ->where('learner_id', '!=', $learner->id)
85	            ->get();
86	
87	        if ($duplicates->isNotEmpty()) {
88	            $identifier->update([
89	                'is_duplicate_candidate' => true,
90	                'duplicate_of_learner_id' => $duplicates->first()->learner_id,
91	                'duplicate_status' => 'pending_review',
92	            ]);
93	        }
94	
95	        return $identifier;
96	    }
97	
98	    /**
99	     * Find potential duplicate learners by fingerprint.
100	     */
101	    public function findDuplicatesByFingerprint(Learner $learner): array
102	    {
103	        if (!$learner->fingerprint) {
104	            return [];
105	        }
106	
107	        return Learner::where('fingerprint', $learner->fingerprint)
108	            ->where('id', '!=', $learner->id)
109	            ->get()
110	            ->toArray();
111	    }
112	
113	    /**
114	     * Find potential duplicates using multiple identity fields.
115	     */
116	    public function findDuplicateCandidates(array $data): array
117	    {
118	        $candidates = collect();
119	
120	        // Check by learner fingerprint
121	        $fingerprint = $this->generateFingerprint($data);
122	        $byFingerprint = Learner::where('fingerprint', $fingerprint)->get();
123	        $candidates = $candidates->merge($byFingerprint);
124	
125	        // Check by email
126	        if (!empty($data['email'])) {
127	            $email = $this->normalizer->normalizeEmail($data['email']);
128	            $byEmail = Learner::where('email', $email)->get();
129	            $candidates = $candidates->merge($byEmail);
130	        }
131	
132	        // Check by phone
133	        if (!empty($data['phone'])) {
134	            $phone = $this->normalizer->normalizePhone($data['phone']);
135	            $byPhone = Learner::where('phone', $phone)->get();
136	            $candidates = $candidates->merge($byPhone);
137	        }
138	
139	        // Check by identifier fingerprints
140	        $identifierFingerprints = [];
141	        if (!empty($data['email'])) {
142	            $identifierFingerprints[] = $this->generateIdentifierFingerprint('email', $data['email']);
143	        }
144	        if (!empty($data['phone'])) {
145	            $identifierFingerprints[] = $this->generateIdentifierFingerprint('phone', $data['phone']);
146	        }
147	
148	        if (!empty($identifierFingerprints)) {
149	            $byIdentifiers = LearnerIdentifier::whereIn('fingerprint', $identifierFingerprints)
150	                ->with('learner')
151	                ->get()
152	                ->pluck('learner')
153	                ->filter();
154	            $candidates = $candidates->merge($byIdentifiers);
155	        }
156	
157	        return $candidates->unique('id')->values()->toArray();
158	    }
159	
160	    /**
161	     * Process deduplication for a learner: compute fingerprint, register identifiers, flag candidates.
162	     */
163	    public function processLearner(Learner $learner): array
164	    {
165	        $fingerprint = $this->computeAndStoreFingerprint($learner);
166	
167	        // Register email identifier
168	        if ($learner->email) {
169	            $this->registerIdentifier($learner, 'email', $learner->email, true);
170	        }
171	
172	        // Register phone identifier
173	        if ($learner->phone) {
174	            $this->registerIdentifier($learner, 'phone', $learner->phone);
175	        }
176	
177	        // Find duplicates
178	        $duplicates = $this->findDuplicatesByFingerprint($learner);
179	
180	        return [
181	            'fingerprint' => $fingerprint,
182	            'duplicate_count' => count($duplicates),
183	            'duplicates' => $duplicates,
184	        ];
185	    }
186	
187	    /**
188	     * Resolve a duplicate candidate: mark as confirmed duplicate or not a duplicate.
189	     */
190	    public function resolveDuplicate(int $identifierId, string $resolution): LearnerIdentifier
191	    {
192	        $validResolutions = ['confirmed_duplicate', 'not_duplicate', 'merged'];
193	
194	        if (!in_array($resolution, $validResolutions)) {
195	            throw new \InvalidArgumentException("Invalid resolution: {$resolution}. Must be one of: " . implode(', ', $validResolutions));
196	        }
197	
198	        $identifier = LearnerIdentifier::findOrFail($identifierId);
199	
200	        $identifier->update([
201	            'duplicate_status' => $resolution,
202	            'is_duplicate_candidate' => $resolution === 'confirmed_duplicate',
203	        ]);
204	
205	        return $identifier;
206	    }
207	}
