8	
9	class ImportService
10	{
11	    private const MAX_ROWS = 10000;
12	
13	    private DataNormalizationService $normalizer;
14	    private DeduplicationService $deduplication;
15	
16	    public function __construct(
17	        DataNormalizationService $normalizer,
18	        DeduplicationService $deduplication
19	    ) {
20	        $this->normalizer = $normalizer;
21	        $this->deduplication = $deduplication;
22	    }
23	
24	    /**
25	     * Import learners from an uploaded CSV/XLSX file.
26	     */
27	    public function importLearners(UploadedFile $file): array
28	    {
29	        $rows = $this->parseFile($file);
30	
31	        if (count($rows) > self::MAX_ROWS) {
32	            return [
33	                'success' => false,
34	                'message' => 'File exceeds maximum of ' . self::MAX_ROWS . ' rows.',
35	                'total_rows' => count($rows),
36	                'imported' => 0,
37	                'failed' => 0,
38	                'errors' => [],
39	            ];
40	        }
41	
42	        $imported = [];
43	        $failed = [];
44	        $duplicates = [];
45	
46	        foreach ($rows as $index => $row) {
47	            $rowNumber = $index + 2; // +2 for 1-based index and header row
48	
49	            // Normalize the row
50	            $normalized = $this->normalizer->normalizeLearnerRow($row);
51	
52	            // Validate the row
53	            $validation = $this->validateRow($normalized);
54	
55	            if ($validation->fails()) {
56	                $failed[] = [
57	                    'row' => $rowNumber,
58	                    'data' => $row,
59	                    'errors' => $validation->errors()->toArray(),
60	                ];
61	                continue;
62	            }
63	
64	            // Check for duplicates before import
65	            $candidates = $this->deduplication->findDuplicateCandidates($normalized);
66	
67	            // Create the learner
68	            $learnerData = $this->mapRowToLearner($normalized);
69	            $learner = Learner::create($learnerData);
70	
71	            // Process deduplication
72	            $dedupResult = $this->deduplication->processLearner($learner);
73	
74	            $importedEntry = [
75	                'row' => $rowNumber,
76	                'learner_id' => $learner->id,
77	            ];
78	
79	            if ($dedupResult['duplicate_count'] > 0 || !empty($candidates)) {
80	                $importedEntry['duplicate_candidates'] = count($candidates);
81	                $duplicates[] = [
82	                    'row' => $rowNumber,
83	                    'learner_id' => $learner->id,
84	                    'candidate_count' => max($dedupResult['duplicate_count'], count($candidates)),
85	                ];
86	            }
87	
88	            $imported[] = $importedEntry;
89	        }
90	
91	        return [
92	            'success' => true,
93	            'message' => 'Import completed.',
94	            'total_rows' => count($rows),
95	            'imported' => count($imported),
96	            'failed' => count($failed),
97	            'duplicate_flags' => count($duplicates),
98	            'imported_records' => $imported,
99	            'failed_records' => $failed,
100	            'duplicate_records' => $duplicates,
101	        ];
102	    }
103	
104	    /**
105	     * Parse a CSV or XLSX file into an array of associative arrays.
106	     */
107	    private function parseFile(UploadedFile $file): array
108	    {
109	        $extension = strtolower($file->getClientOriginalExtension());
110	
111	        if ($extension === 'csv' || $extension === 'txt') {
112	            return $this->parseCsv($file);
113	        }
114	
115	        return $this->parseSpreadsheet($file);
116	    }
117	
118	    /**
119	     * Parse a CSV file.
120	     */
121	    private function parseCsv(UploadedFile $file): array
122	    {
123	        $rows = [];
124	        $handle = fopen($file->getRealPath(), 'r');
125	
126	        if ($handle === false) {
127	            return [];
128	        }
129	
130	        $headers = null;
131	
132	        while (($data = fgetcsv($handle)) !== false) {
133	            if ($headers === null) {
134	                $headers = array_map(fn ($h) => strtolower(trim($h)), $data);
135	                continue;
136	            }
137	
138	            if (count($data) !== count($headers)) {
139	                // Pad or trim to match header count
140	                $data = array_pad($data, count($headers), '');
141	                $data = array_slice($data, 0, count($headers));
142	            }
143	
144	            $row = array_combine($headers, $data);
145	            $rows[] = $row;
146	        }
147	
148	        fclose($handle);
149	
150	        return $rows;
151	    }
152	
153	    /**
154	     * Parse an XLSX/XLS file using maatwebsite/excel or basic XML parsing.
155	     */
156	    private function parseSpreadsheet(UploadedFile $file): array
157	    {
158	        // Use PhpSpreadsheet via maatwebsite/excel if available
159	        if (class_exists(\PhpOffice\PhpSpreadsheet\IOFactory::class)) {
160	            return $this->parseWithPhpSpreadsheet($file);
161	        }
162	
163	        // Fallback: try to read as CSV (user may have mis-named the file)
164	        return $this->parseCsv($file);
165	    }
166	
167	    /**
168	     * Parse using PhpSpreadsheet directly.
169	     */
170	    private function parseWithPhpSpreadsheet(UploadedFile $file): array
171	    {
172	        $spreadsheet = \PhpOffice\PhpSpreadsheet\IOFactory::load($file->getRealPath());
173	        $worksheet = $spreadsheet->getActiveSheet();
174	        $rows = [];
175	        $headers = null;
176	
177	        foreach ($worksheet->getRowIterator() as $row) {
178	            $cellIterator = $row->getCellIterator();
179	            $cellIterator->setIterateOnlyExistingCells(false);
180	
181	            $data = [];
182	            foreach ($cellIterator as $cell) {
183	                $data[] = $cell->getValue();
184	            }
185	
186	            if ($headers === null) {
187	                $headers = array_map(fn ($h) => strtolower(trim((string) $h)), $data);
188	                continue;
189	            }
190	
191	            if (count($data) !== count($headers)) {
192	                $data = array_pad($data, count($headers), '');
193	                $data = array_slice($data, 0, count($headers));
194	            }
195	
196	            $row = array_combine($headers, array_map(fn ($v) => (string) ($v ?? ''), $data));
197	
198	            // Skip entirely empty rows
199	            if (implode('', array_values($row)) === '') {
200	                continue;
201	            }
202	
203	            $rows[] = $row;
