5	use Illuminate\Support\Facades\Crypt;
6	
7	class EncryptionService
8	{
9	    /**
10	     * Encrypt a value. Returns null if input is null.
11	     */
12	    public function encrypt(?string $value): ?string
13	    {
14	        if ($value === null || $value === '') {
15	            return null;
16	        }
17	
18	        return Crypt::encryptString($value);
19	    }
20	
21	    /**
22	     * Decrypt a value. Returns null if input is null or decryption fails.
23	     */
24	    public function decrypt(?string $value): ?string
25	    {
26	        if ($value === null || $value === '') {
27	            return null;
28	        }
29	
30	        try {
31	            return Crypt::decryptString($value);
32	        } catch (\Exception) {
33	            return $value; // Return as-is if not encrypted or decryption fails
34	        }
35	    }
36	
37	    /**
38	     * Mask an email address: show first 2 chars + domain.
39	     * e.g., "john.doe@example.com" → "jo***@example.com"
40	     */
41	    public function maskEmail(?string $email): ?string
42	    {
43	        if ($email === null || $email === '') {
44	            return null;
45	        }
46	
47	        $parts = explode('@', $email);
48	        if (count($parts) !== 2) {
49	            return '***';
50	        }
51	
52	        $local = $parts[0];
53	        $domain = $parts[1];
54	
55	        $visible = min(2, strlen($local));
56	        $masked = substr($local, 0, $visible) . str_repeat('*', 3);
57	
58	        return $masked . '@' . $domain;
59	    }
60	
61	    /**
62	     * Mask a phone number: show last 4 digits.
63	     * e.g., "+15551234567" → "***4567"
64	     */
65	    public function maskPhone(?string $phone): ?string
66	    {
67	        if ($phone === null || $phone === '') {
68	            return null;
69	        }
70	
71	        $digits = preg_replace('/\D/', '', $phone);
72	
73	        if (strlen($digits) <= 4) {
74	            return $phone;
75	        }
76	
77	        return '***' . substr($digits, -4);
78	    }
79	
80	    /**
81	     * Mask a generic string: show first and last char with asterisks.
82	     * e.g., "John Smith" → "J********h"
83	     */
84	    public function maskGeneric(?string $value): ?string
85	    {
86	        if ($value === null || $value === '') {
87	            return null;
88	        }
89	
90	        $len = strlen($value);
91	
92	        if ($len <= 2) {
93	            return str_repeat('*', $len);
94	        }
95	
96	        return $value[0] . str_repeat('*', $len - 2) . $value[$len - 1];
97	    }
98	
99	    /**
100	     * Fully redact a value.
101	     */
102	    public function redact(?string $value): string
103	    {
104	        return '[REDACTED]';
105	    }
106	}
