     * Scope an Eloquent query to only return records the user is authorized to see.
     * Admin and planner get unrestricted access; reviewer and field_agent are
     * scoped to records they own or are assigned to.
     */
    protected function scopeQueryForUser($query, $user): void
    {
        if ($user->hasRole('admin') || $user->hasRole('planner')) {
            return;
        }

        $userId = $user->id;
        $query->where(function ($q) use ($userId) {
            $q->where('created_by', $userId)
                ->orWhere('last_actor_id', $userId)
                ->orWhere('user_id', $userId)
                ->orWhere('booked_by', $userId)
                ->orWhere('reviewer_id', $userId);
        });
    }

    /**
     * Ensure the authenticated user may mutate (update/delete) the given record.
     * More restrictive than read access.
     */"}

