1	<?php
2	
3	namespace App\Services;
4	
5	use App\Models\Booking;
6	use App\Models\Resource;
7	use App\Models\WaitlistEntry;
8	use Carbon\Carbon;
9	use Illuminate\Support\Facades\DB;
10	use Illuminate\Support\Str;
11	
12	class BookingService
13	{
14	    private const HOLD_DURATION_MINUTES = 5;
15	    private const WAITLIST_OFFER_MINUTES = 10;
16	    private const MIN_LEAD_TIME_HOURS = 2;
17	    private const RESCHEDULE_WINDOW_HOURS = 24;
18	    private const SLOT_INCREMENT_MINUTES = 15;
19	
20	    /**
21	     * Create a provisional hold for a booking.
22	     */
23	    public function createProvisionalHold(array $data): Booking
24	    {
25	        $resourceId = $data['resource_id'];
26	        $learnerId = $data['learner_id'];
27	        $startTime = Carbon::parse($data['start_time']);
28	        $endTime = Carbon::parse($data['end_time']);
29	        $idempotencyKey = $data['idempotency_key'] ?? Str::uuid()->toString();
30	        $bookedBy = $data['booked_by'] ?? null;
31	
32	        // Check idempotency — return existing booking if key matches
33	        $existing = Booking::where('idempotency_key', $idempotencyKey)->first();
34	        if ($existing) {
35	            return $existing;
36	        }
37	
38	        // Validate slot increment
39	        $this->validateSlotIncrement($startTime, $endTime);
40	
41	        // Validate lead time
42	        $this->validateLeadTime($startTime);
43	
44	        // Expire any stale provisional holds
45	        $this->expireStaleHolds();
46	
47	        // Conflict check + create inside a single transaction with row locking
48	        return DB::transaction(function () use ($resourceId, $learnerId, $startTime, $endTime, $idempotencyKey, $bookedBy) {
49	            $this->checkConflictsWithLock($resourceId, $startTime, $endTime);
50	
51	            return Booking::create([
52	                'resource_id' => $resourceId,
53	                'learner_id' => $learnerId,
54	                'booked_by' => $bookedBy,
55	                'idempotency_key' => $idempotencyKey,
56	                'status' => Booking::STATUS_PROVISIONAL,
57	                'start_time' => $startTime,
58	                'end_time' => $endTime,
59	                'version' => 1,
60	                'hold_expires_at' => now()->addMinutes(self::HOLD_DURATION_MINUTES),
61	            ]);
62	        });
63	    }
64	
65	    /**
66	     * Confirm a provisional hold into a final booking.
67	     */
68	    public function confirmBooking(Booking $booking, int $expectedVersion = 0): Booking
69	    {
70	        if (!$booking->isProvisional()) {
71	            throw new \InvalidArgumentException('Only provisional bookings can be confirmed.');
72	        }
73	
74	        if ($booking->isHoldExpired()) {
75	            $booking->update(['status' => Booking::STATUS_CANCELLED, 'cancelled_at' => now(), 'cancellation_type' => 'hold_expired']);
76	            throw new \InvalidArgumentException('Provisional hold has expired.');
77	        }
78	
79	        return DB::transaction(function () use ($booking, $expectedVersion) {
80	            // Re-fetch with pessimistic lock to prevent race conditions
81	            $locked = Booking::lockForUpdate()->find($booking->id);
82	
83	            if (!$locked || !$locked->isProvisional()) {
84	                throw new \InvalidArgumentException('Booking is no longer provisional.');
85	            }
86	
87	            // Optimistic version check if caller provided one
88	            if ($expectedVersion > 0 && $locked->version !== $expectedVersion) {
89	                throw new \InvalidArgumentException(
90	                    "Version conflict: expected {$expectedVersion}, found {$locked->version}."
91	                );
92	            }
93	
94	            $this->checkConflictsWithLock($locked->resource_id, $locked->start_time, $locked->end_time, $locked->id);
95	
96	            $locked->update([
97	                'status' => Booking::STATUS_CONFIRMED,
98	                'confirmed_at' => now(),
99	                'hold_expires_at' => null,
100	            ]);
101	
102	            return $locked->fresh();
103	        });
104	    }
105	
106	    /**
107	     * Cancel a booking. Creates late_cancel if within 24 hours of start.
108	     */
109	    public function cancelBooking(Booking $booking, ?string $notes = null): Booking
110	    {
111	        if (!$booking->isActive()) {
112	            throw new \InvalidArgumentException('This booking cannot be cancelled.');
113	        }
114	
115	        $isLateCancel = $booking->start_time->diffInHours(now(), false) > -(self::RESCHEDULE_WINDOW_HOURS);
116	        $status = $isLateCancel ? Booking::STATUS_LATE_CANCEL : Booking::STATUS_CANCELLED;
117	        $cancellationType = $isLateCancel ? 'late_cancel' : 'standard';
118	
119	        $booking->update([
120	            'status' => $status,
121	            'cancelled_at' => now(),
122	            'cancellation_type' => $cancellationType,
123	            'notes' => $notes,
124	        ]);
125	
126	        // Trigger waitlist backfill
127	        $this->offerToWaitlist($booking->resource_id, $booking->start_time, $booking->end_time);
128	
129	        return $booking->fresh();
130	    }
131	
132	    /**
133	     * Reschedule a booking to a new time.
134	     */
135	    public function rescheduleBooking(Booking $booking, Carbon $newStartTime, Carbon $newEndTime, int $expectedVersion = 0): Booking
136	    {
137	        if ($booking->status !== Booking::STATUS_CONFIRMED) {
138	            throw new \InvalidArgumentException('Only confirmed bookings can be rescheduled.');
139	        }
140	
141	        // Check 24-hour reschedule window
142	        $hoursUntilStart = now()->diffInHours($booking->start_time, false);
143	        if ($hoursUntilStart < self::RESCHEDULE_WINDOW_HOURS) {
144	            throw new \InvalidArgumentException(
145	                'Reschedules must be made at least ' . self::RESCHEDULE_WINDOW_HOURS . ' hours before the original start time.'
146	            );
147	        }
148	
149	        $this->validateSlotIncrement($newStartTime, $newEndTime);
150	        $this->validateLeadTime($newStartTime);
151	
152	        return DB::transaction(function () use ($booking, $newStartTime, $newEndTime, $expectedVersion) {
153	            $locked = Booking::lockForUpdate()->find($booking->id);
154	
155	            if (!$locked || $locked->status !== Booking::STATUS_CONFIRMED) {
156	                throw new \InvalidArgumentException('Booking is no longer confirmed.');
157	            }
158	
159	            // Optimistic version check if caller provided one
160	            if ($expectedVersion > 0 && $locked->version !== $expectedVersion) {
161	                throw new \InvalidArgumentException(
162	                    "Version conflict: expected {$expectedVersion}, found {$locked->version}."
163	                );
164	            }
165	
166	            $this->checkConflictsWithLock($locked->resource_id, $newStartTime, $newEndTime, $locked->id);
167	
168	            $locked->update([
169	                'start_time' => $newStartTime,
170	                'end_time' => $newEndTime,
171	                'version' => $locked->version + 1,
172	            ]);
173	
174	            return $locked->fresh();
175	        });
176	    }
177	
178	    /**
179	     * Add a learner to the waitlist for a resource slot.
180	     */
181	    public function addToWaitlist(array $data): WaitlistEntry
182	    {
183	        $maxPosition = WaitlistEntry::where('resource_id', $data['resource_id'])
184	            ->where('status', WaitlistEntry::STATUS_WAITING)
185	            ->max('position') ?? 0;
186	
187	        return WaitlistEntry::create([
188	            'resource_id' => $data['resource_id'],
189	            'learner_id' => $data['learner_id'],
190	            'desired_start_time' => $data['start_time'],
191	            'desired_end_time' => $data['end_time'],
192	            'status' => WaitlistEntry::STATUS_WAITING,
193	            'position' => $maxPosition + 1,
194	        ]);
195	    }
196	
197	    /**
198	     * Accept a waitlist offer and create a confirmed booking.
199	     */
200	    public function acceptWaitlistOffer(WaitlistEntry $entry, int $bookedBy): Booking
201	    {
202	        if ($entry->status !== WaitlistEntry::STATUS_OFFERED) {
203	            throw new \InvalidArgumentException('This waitlist entry does not have an active offer.');
204	        }
205	
206	        if ($entry->isOfferExpired()) {
207	            $entry->update(['status' => WaitlistEntry::STATUS_EXPIRED]);
208	            throw new \InvalidArgumentException('The waitlist offer has expired.');
209	        }
210	
211	        return DB::transaction(function () use ($entry, $bookedBy) {
212	            $this->checkConflictsWithLock($entry->resource_id, $entry->desired_start_time, $entry->desired_end_time);
213	
214	            $entry->update([
215	                'status' => WaitlistEntry::STATUS_ACCEPTED,
216	                'accepted_at' => now(),
217	            ]);
218	
219	            return Booking::create([
220	                'resource_id' => $entry->resource_id,
221	                'learner_id' => $entry->learner_id,
222	                'booked_by' => $bookedBy,
223	                'idempotency_key' => Str::uuid()->toString(),
224	                'status' => Booking::STATUS_CONFIRMED,
225	                'start_time' => $entry->desired_start_time,
226	                'end_time' => $entry->desired_end_time,
227	                'version' => 1,
228	                'confirmed_at' => now(),
229	            ]);
230	        });
231	    }
232	
233	    /**
234	     * Offer the next waitlist entry for a freed slot.
235	     */
236	    private function offerToWaitlist(int $resourceId, Carbon $startTime, Carbon $endTime): void
237	    {
238	        $entry = WaitlistEntry::where('resource_id', $resourceId)
