3	namespace App\Http\Middleware;
4	
5	use Closure;
6	use Illuminate\Http\Request;
7	use Illuminate\Support\Facades\Log;
8	use Symfony\Component\HttpFoundation\Response;
9	
10	class LogRequestResponse
11	{
12	    /**
13	     * Sensitive fields that should not be logged.
14	     */
15	    private const REDACTED_FIELDS = [
16	        'password',
17	        'password_confirmation',
18	        'current_password',
19	        'token',
20	        'api_token',
21	        'authorization',
22	        'email',
23	        'phone',
24	        'guardian_contact',
25	        'guardian_name',
26	        'address',
27	        'date_of_birth',
28	        'first_name',
29	        'last_name',
30	        'answers',
31	        'ssn',
32	        'national_id',
33	    ];
34	
35	    public function handle(Request $request, Closure $next): Response
36	    {
37	        $startTime = microtime(true);
38	
39	        $response = $next($request);
40	
41	        $duration = round((microtime(true) - $startTime) * 1000, 2);
42	
43	        $this->logRequest($request, $response, $duration);
44	
45	        return $response;
46	    }
47	
48	    private function logRequest(Request $request, Response $response, float $durationMs): void
49	    {
50	        $statusCode = $response->getStatusCode();
51	        $method = $request->method();
52	        $path = $request->path();
53	        $userId = $request->user()?->id;
54	
55	        $context = [
56	            'method' => $method,
57	            'path' => $path,
58	            'status' => $statusCode,
59	            'duration_ms' => $durationMs,
60	            'ip' => $request->ip(),
61	            'user_id' => $userId,
62	            'user_agent' => substr($request->userAgent() ?? '', 0, 200),
63	        ];
64	
65	        // Include sanitized request params for non-GET requests
66	        if (!$request->isMethod('GET')) {
67	            $context['params'] = $this->sanitizeParams($request->all());
68	        }
69	
70	        // Log level based on status code
71	        $message = "{$method} /{$path} → {$statusCode} ({$durationMs}ms)";
72	
73	        if ($statusCode >= 500) {
74	            Log::error($message, $context);
75	        } elseif ($statusCode >= 400) {
76	            Log::warning($message, $context);
77	        } else {
78	            Log::info($message, $context);
79	        }
80	    }
81	
82	    private function sanitizeParams(array $params): array
83	    {
84	        $sanitized = [];
85	
86	        foreach ($params as $key => $value) {
87	            if (in_array(strtolower($key), self::REDACTED_FIELDS)) {
88	                $sanitized[$key] = '[REDACTED]';
89	            } elseif (is_array($value)) {
90	                $sanitized[$key] = $this->sanitizeParams($value);
91	            } else {
92	                $sanitized[$key] = $value;
93	            }
94	        }
95	
96	        return $sanitized;
97	    }
98	}
