138	    /**
139	     * Process an approval decision at the current level.
140	     */
141	    public function processApproval(Enrollment $enrollment, User $reviewer, string $decision, ?string $comments = null, ?string $reasonCode = null): Enrollment
142	    {
143	        if (!in_array($decision, ['approved', 'rejected'])) {
144	            throw new \InvalidArgumentException("Decision must be 'approved' or 'rejected'.");
145	        }
146	
147	        $currentLevel = $enrollment->current_approval_level;
148	
149	        // Enforce required role for approval (not rejection — any reviewer can reject)
150	        if ($decision === 'approved') {
151	            $this->enforceApprovalLevelRole($enrollment, $currentLevel, $reviewer);
152	        }
153	
154	        // Find or create the approval for the current level
155	        $approval = Approval::where('enrollment_id', $enrollment->id)
156	            ->where('level', $currentLevel)
157	            ->first();
158	
159	        if (!$approval) {
160	            $approval = Approval::create([
161	                'enrollment_id' => $enrollment->id,
162	                'reviewer_id' => $reviewer->id,
163	                'level' => $currentLevel,
164	                'status' => 'in_review',
165	            ]);
166	        }
167	
168	        // Record the decision
169	        $approval->update([
170	            'reviewer_id' => $reviewer->id,
171	            'status' => $decision,
172	            'decision' => $decision,
173	            'comments' => $comments,
174	            'reason_code' => $reasonCode,
175	            'decided_at' => now(),
176	        ]);
177	
178	        if ($decision === 'rejected') {
179	            return $this->transition($enrollment, Enrollment::STATUS_REJECTED, $reviewer, $reasonCode ?? 'rejected', $comments);
180	        }
181	
182	        // Approved — check if more levels needed
183	        if ($currentLevel < $enrollment->max_approval_levels) {
184	            // Advance to next level
185	            $nextLevel = $currentLevel + 1;
186	            $enrollment->update(['current_approval_level' => $nextLevel]);
187	
188	            // Create next-level approval record
189	            Approval::create([
190	                'enrollment_id' => $enrollment->id,
191	                'level' => $nextLevel,
192	                'status' => 'pending',
193	            ]);
194	
195	            return $enrollment->fresh();
196	        }
197	
198	        // All levels approved
199	        return $this->transition($enrollment, Enrollment::STATUS_APPROVED, $reviewer, $reasonCode ?? 'fully_approved', $comments);
200	    }
