234	    /**
235	     * Enforce that the reviewer has the required role for the given approval level.
236	     */
237	    private function enforceApprovalLevelRole(Enrollment $enrollment, int $level, User $reviewer): void
238	    {
239	        $workflowMetadata = $enrollment->workflow_metadata ?? [];
240	        $levelConfigs = $workflowMetadata['level_config'] ?? [];
241	
242	        foreach ($levelConfigs as $config) {
243	            if (($config['level'] ?? null) === $level && !empty($config['required_role'])) {
244	                $requiredRole = $config['required_role'];
245	                if (!$reviewer->hasRole($requiredRole) && !$reviewer->hasRole('admin')) {
246	                    throw new \InvalidArgumentException(
247	                        "Approval level {$level} requires the '{$requiredRole}' role. " .
248	                        'The current reviewer does not have the required role.'
249	                    );
250	                }
251	                return;
252	            }
253	        }
254	    }
