267	            'current_approval_level' => $enrollment->current_approval_level,
268	            'max_approval_levels' => $enrollment->max_approval_levels,
269	            'requires_guardian_approval' => $enrollment->requires_guardian_approval,
270	            'allowed_transitions' => $enrollment->getAllowedTransitions(),
271	            'approvals' => $approvals->map(fn ($a) => [
