16	     * Password must be at least 12 characters with uppercase, lowercase, digit, and special character.
17	     */
18	    private const PASSWORD_PATTERN = '/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[\W_]).{12,}$/';
