22	    public function login(Request $request): JsonResponse
23	    {
24	        $request->validate([
25	            'username' => 'required|string',
26	            'password' => 'required|string',
27	        ]);
28	
29	        $user = User::where('username', $request->username)->first();
30	
31	        if (!$user) {
32	            return response()->json([
33	                'error' => 'Unauthorized',
34	                'message' => 'Invalid credentials.',
35	            ], 401);
36	        }
37	
38	        if ($user->isLockedOut()) {
39	            return response()->json([
40	                'error' => 'Locked',
41	                'message' => 'Account is temporarily locked due to too many failed login attempts.',
42	                'locked_until' => $user->locked_until->toIso8601String(),
43	            ], 423);
44	        }
45	
46	        if (!$user->is_active) {
47	            return response()->json([
48	                'error' => 'Unauthorized',
49	                'message' => 'Account is inactive.',
50	            ], 401);
51	        }
52	
53	        if (!Hash::check($request->password, $user->password)) {
54	            $user->incrementFailedAttempts();
55	
56	            $response = [
57	                'error' => 'Unauthorized',
58	                'message' => 'Invalid credentials.',
59	            ];
60	
61	            if ($user->isLockedOut()) {
62	                $response['message'] = 'Account locked due to too many failed attempts.';
63	                $response['locked_until'] = $user->locked_until->toIso8601String();
64	            }
65	
66	            return response()->json($response, 401);
67	        }
68	
69	        // Successful login
70	        $user->resetFailedAttempts();
71	        $user->update(['last_login_at' => now()]);
72	
73	        // Generate token
74	        $plainToken = Str::random(64);
75	        $hashedToken = hash('sha256', $plainToken);
76	
77	        $apiToken = ApiToken::create([
78	            'user_id' => $user->id,
79	            'token' => $hashedToken,
80	            'expires_at' => now()->addHours(self::TOKEN_LIFETIME_HOURS),
81	            'ip_address' => $request->ip(),
82	            'user_agent' => $request->userAgent(),
83	        ]);
84	
85	        $user->load('role.permissions');
86	
87	        return response()->json([
88	            'message' => 'Login successful.',
89	            'token' => $plainToken,
90	            'token_type' => 'Bearer',
91	            'expires_at' => $apiToken->expires_at->toIso8601String(),
92	            'user' => new UserResource($user),
93	        ]);
94	    }
