23	            'is_active' => $this->is_active,
24	            'last_login_at' => $this->last_login_at?->toIso8601String(),
25	            'role' => $this->whenLoaded('role', function () {
26	                return [
27	                    'name' => $this->role->name,
28	                    'slug' => $this->role->slug,
29	                    'permissions' => $this->role->relationLoaded('permissions')
30	                        ? $this->role->permissions->pluck('slug')
31	                        : null,
32	                ];
33	            }),
34	        ];
35	    }
36	
37	    private function canViewFullPii(Request $request): bool
38	    {
39	        $user = $request->user();
40	
41	        if (!$user) {
42	            return false;
43	        }
44	
45	        // Users can always see their own data
46	        if ($user->id === $this->id) {
47	            return true;
48	        }
49	
50	        return $user->hasRole('admin') || $user->hasRole('planner');
