47	            'description' => $request->description,
48	            'type' => $request->type,
49	            'filters' => $request->filters,
50	            'columns' => $request->columns,
51	            'output_format' => $request->output_format ?? 'csv',
52	            'created_by' => $request->user()->id,
53	            'metadata' => $request->metadata,
