66	        return response()->json(['data' => $report]);
67	    }
68	
69	    public function update(Request $request, int $id): JsonResponse
70	    {
71	        $request->validate([
72	            'name' => 'sometimes|required|string|max:255',
73	            'description' => 'nullable|string|max:2000',
74	            'type' => 'sometimes|required|string|in:learners,enrollments,bookings,audit',
75	            'filters' => 'nullable|array',
