28	            'email' => $canViewFullPii ? $email : $encryptionService->maskEmail($email),
29	            'phone' => $canViewFullPii ? $phone : $encryptionService->maskPhone($phone),
30	            'gender' => $this->gender,
31	            'nationality' => $this->nationality,
32	            'language' => $this->language,
33	            'address' => $this->address,
34	            'guardian_name' => $this->guardian_name,
35	            'guardian_contact' => $canViewFullPii ? $guardianContact : $encryptionService->maskPhone($guardianContact),
36	            'status' => $this->status,
37	            'is_minor' => $this->isMinor(),
38	            'fingerprint' => $this->fingerprint,
