20	    /**
21	     * Create a provisional hold for a booking.
22	     */
23	    public function createProvisionalHold(array $data): Booking
24	    {
25	        $resourceId = $data['resource_id'];
26	        $learnerId = $data['learner_id'];
27	        $startTime = Carbon::parse($data['start_time']);
28	        $endTime = Carbon::parse($data['end_time']);
29	        $idempotencyKey = $data['idempotency_key'] ?? Str::uuid()->toString();
30	        $bookedBy = $data['booked_by'] ?? null;
31	
32	        // Check idempotency — return existing booking if key matches
33	        $existing = Booking::where('idempotency_key', $idempotencyKey)->first();
34	        if ($existing) {
35	            return $existing;
36	        }
37	
38	        // Validate slot increment
39	        $this->validateSlotIncrement($startTime, $endTime);
40	
41	        // Validate lead time
42	        $this->validateLeadTime($startTime);
43	
44	        // Expire any stale provisional holds
45	        $this->expireStaleHolds();
46	
47	        // Conflict check + create inside a single transaction with row locking
48	        return DB::transaction(function () use ($resourceId, $learnerId, $startTime, $endTime, $idempotencyKey, $bookedBy) {
49	            $this->checkConflictsWithLock($resourceId, $startTime, $endTime);
50	
51	            return Booking::create([
52	                'resource_id' => $resourceId,
53	                'learner_id' => $learnerId,
54	                'booked_by' => $bookedBy,
55	                'idempotency_key' => $idempotencyKey,
56	                'status' => Booking::STATUS_PROVISIONAL,
57	                'start_time' => $startTime,
58	                'end_time' => $endTime,
59	                'version' => 1,
60	                'hold_expires_at' => now()->addMinutes(self::HOLD_DURATION_MINUTES),
61	            ]);
62	        });
63	    }
