106	    /**
107	     * Cancel a booking. Creates late_cancel if within 24 hours of start.
108	     */
109	    public function cancelBooking(Booking $booking, ?string $notes = null): Booking
110	    {
111	        if (!$booking->isActive()) {
112	            throw new \InvalidArgumentException('This booking cannot be cancelled.');
113	        }
114	
115	        $isLateCancel = $booking->start_time->diffInHours(now(), false) > -(self::RESCHEDULE_WINDOW_HOURS);
116	        $status = $isLateCancel ? Booking::STATUS_LATE_CANCEL : Booking::STATUS_CANCELLED;
117	        $cancellationType = $isLateCancel ? 'late_cancel' : 'standard';
118	
119	        $booking->update([
120	            'status' => $status,
121	            'cancelled_at' => now(),
122	            'cancellation_type' => $cancellationType,
123	            'notes' => $notes,
124	        ]);
125	
126	        // Trigger waitlist backfill
127	        $this->offerToWaitlist($booking->resource_id, $booking->start_time, $booking->end_time);
128	
129	        return $booking->fresh();
130	    }
131	
132	    /**
133	     * Reschedule a booking to a new time.
134	     */
135	    public function rescheduleBooking(Booking $booking, Carbon $newStartTime, Carbon $newEndTime, int $expectedVersion = 0): Booking
136	    {
137	        if ($booking->status !== Booking::STATUS_CONFIRMED) {
138	            throw new \InvalidArgumentException('Only confirmed bookings can be rescheduled.');
139	        }
140	
141	        // Check 24-hour reschedule window
142	        $hoursUntilStart = now()->diffInHours($booking->start_time, false);
143	        if ($hoursUntilStart < self::RESCHEDULE_WINDOW_HOURS) {
144	            throw new \InvalidArgumentException(
145	                'Reschedules must be made at least ' . self::RESCHEDULE_WINDOW_HOURS . ' hours before the original start time.'
146	            );
147	        }
148	
149	        $this->validateSlotIncrement($newStartTime, $newEndTime);
150	        $this->validateLeadTime($newStartTime);
151	
152	        return DB::transaction(function () use ($booking, $newStartTime, $newEndTime, $expectedVersion) {
153	            $locked = Booking::lockForUpdate()->find($booking->id);
154	
155	            if (!$locked || $locked->status !== Booking::STATUS_CONFIRMED) {
156	                throw new \InvalidArgumentException('Booking is no longer confirmed.');
157	            }
158	
159	            // Optimistic version check if caller provided one
160	            if ($expectedVersion > 0 && $locked->version !== $expectedVersion) {
161	                throw new \InvalidArgumentException(
162	                    "Version conflict: expected {$expectedVersion}, found {$locked->version}."
163	                );
164	            }
165	
166	            $this->checkConflictsWithLock($locked->resource_id, $newStartTime, $newEndTime, $locked->id);
167	
168	            $locked->update([
169	                'start_time' => $newStartTime,
170	                'end_time' => $newEndTime,
171	                'version' => $locked->version + 1,
172	            ]);
173	
174	            return $locked->fresh();
175	        });
176	    }
