178	    /**
179	     * Add a learner to the waitlist for a resource slot.
180	     */
181	    public function addToWaitlist(array $data): WaitlistEntry
182	    {
183	        $maxPosition = WaitlistEntry::where('resource_id', $data['resource_id'])
184	            ->where('status', WaitlistEntry::STATUS_WAITING)
185	            ->max('position') ?? 0;
186	
187	        return WaitlistEntry::create([
188	            'resource_id' => $data['resource_id'],
189	            'learner_id' => $data['learner_id'],
190	            'desired_start_time' => $data['start_time'],
191	            'desired_end_time' => $data['end_time'],
192	            'status' => WaitlistEntry::STATUS_WAITING,
193	            'position' => $maxPosition + 1,
194	        ]);
195	    }
196	
197	    /**
198	     * Accept a waitlist offer and create a confirmed booking.
199	     */
200	    public function acceptWaitlistOffer(WaitlistEntry $entry, int $bookedBy): Booking
201	    {
202	        if ($entry->status !== WaitlistEntry::STATUS_OFFERED) {
203	            throw new \InvalidArgumentException('This waitlist entry does not have an active offer.');
204	        }
205	
206	        if ($entry->isOfferExpired()) {
207	            $entry->update(['status' => WaitlistEntry::STATUS_EXPIRED]);
208	            throw new \InvalidArgumentException('The waitlist offer has expired.');
209	        }
210	
211	        return DB::transaction(function () use ($entry, $bookedBy) {
212	            $this->checkConflictsWithLock($entry->resource_id, $entry->desired_start_time, $entry->desired_end_time);
213	
214	            $entry->update([
215	                'status' => WaitlistEntry::STATUS_ACCEPTED,
216	                'accepted_at' => now(),
217	            ]);
218	
219	            return Booking::create([
220	                'resource_id' => $entry->resource_id,
221	                'learner_id' => $entry->learner_id,
222	                'booked_by' => $bookedBy,
223	                'idempotency_key' => Str::uuid()->toString(),
224	                'status' => Booking::STATUS_CONFIRMED,
225	                'start_time' => $entry->desired_start_time,
226	                'end_time' => $entry->desired_end_time,
227	                'version' => 1,
228	                'confirmed_at' => now(),
229	            ]);
230	        });
231	    }
