233	    /**
234	     * Offer the next waitlist entry for a freed slot.
235	     */
236	    private function offerToWaitlist(int $resourceId, Carbon $startTime, Carbon $endTime): void
237	    {
238	        $entry = WaitlistEntry::where('resource_id', $resourceId)
239	            ->where('status', WaitlistEntry::STATUS_WAITING)
240	            ->where('desired_start_time', $startTime)
241	            ->where('desired_end_time', $endTime)
242	            ->orderBy('position', 'asc')
243	            ->first();
244	
245	        if ($entry) {
246	            $entry->update([
247	                'status' => WaitlistEntry::STATUS_OFFERED,
248	                'offered_at' => now(),
249	                'offer_expires_at' => now()->addMinutes(self::WAITLIST_OFFER_MINUTES),
250	            ]);
251	        }
252	    }
