254	    /**
255	     * Expire stale provisional holds and waitlist offers.
256	     */
257	    public function expireStaleHolds(): void
258	    {
259	        Booking::where('status', Booking::STATUS_PROVISIONAL)
260	            ->where('hold_expires_at', '<', now())
261	            ->update([
262	                'status' => Booking::STATUS_CANCELLED,
263	                'cancelled_at' => now(),
264	                'cancellation_type' => 'hold_expired',
265	            ]);
266	
267	        WaitlistEntry::where('status', WaitlistEntry::STATUS_OFFERED)
268	            ->where('offer_expires_at', '<', now())
269	            ->update([
270	                'status' => WaitlistEntry::STATUS_EXPIRED,
271	            ]);
272	    }
