274	    /**
275	     * Validate start/end times are in 15-minute increments.
276	     */
277	    private function validateSlotIncrement(Carbon $startTime, Carbon $endTime): void
278	    {
279	        if ($startTime->minute % self::SLOT_INCREMENT_MINUTES !== 0) {
280	            throw new \InvalidArgumentException('Start time must be in ' . self::SLOT_INCREMENT_MINUTES . '-minute increments.');
281	        }
282	
283	        if ($endTime->minute % self::SLOT_INCREMENT_MINUTES !== 0) {
284	            throw new \InvalidArgumentException('End time must be in ' . self::SLOT_INCREMENT_MINUTES . '-minute increments.');
285	        }
286	
287	        if ($endTime->lte($startTime)) {
288	            throw new \InvalidArgumentException('End time must be after start time.');
289	        }
290	    }
291	
292	    /**
293	     * Validate minimum lead time before booking.
294	     */
295	    private function validateLeadTime(Carbon $startTime): void
296	    {
297	        $hoursUntilStart = now()->diffInHours($startTime, false);
298	
299	        if ($hoursUntilStart < self::MIN_LEAD_TIME_HOURS) {
300	            throw new \InvalidArgumentException(
301	                'Bookings must be made at least ' . self::MIN_LEAD_TIME_HOURS . ' hours in advance.'
302	            );
303	        }
304	    }
305	
306	    /**
307	     * Check for booking conflicts with pessimistic row locking to prevent oversell.
308	     */
309	    private function checkConflictsWithLock(int $resourceId, Carbon $startTime, Carbon $endTime, ?int $excludeBookingId = null): void
310	    {
311	        $query = Booking::lockForUpdate()
312	            ->where('resource_id', $resourceId)
313	            ->whereIn('status', [Booking::STATUS_PROVISIONAL, Booking::STATUS_CONFIRMED])
314	            ->where('start_time', '<', $endTime)
315	            ->where('end_time', '>', $startTime);
316	
317	        if ($excludeBookingId) {
318	            $query->where('id', '!=', $excludeBookingId);
319	        }
320	
321	        $resource = Resource::findOrFail($resourceId);
322	        $conflictCount = $query->count();
323	
324	        if ($conflictCount >= $resource->capacity) {
325	            throw new \InvalidArgumentException(
326	                'Resource is fully booked for the requested time slot. ' .
327	                "Capacity: {$resource->capacity}, Current bookings: {$conflictCount}."
328	            );
329	        }
330	    }
