16	    public const STATUS_DRAFT = 'draft';
17	    public const STATUS_SUBMITTED = 'submitted';
18	    public const STATUS_UNDER_REVIEW = 'under_review';
19	    public const STATUS_APPROVED = 'approved';
20	    public const STATUS_REJECTED = 'rejected';
21	    public const STATUS_ENROLLED = 'enrolled';
22	    public const STATUS_WAITLISTED = 'waitlisted';
23	    public const STATUS_CANCELLED = 'cancelled';
24	    public const STATUS_COMPLETED = 'completed';
25	    public const STATUS_REFUNDED = 'refunded';
26	
27	    /**
28	     * Valid state transitions: current_status => [allowed next statuses]
29	     */
30	    public const TRANSITIONS = [
31	        self::STATUS_DRAFT => [self::STATUS_SUBMITTED],
32	        self::STATUS_SUBMITTED => [self::STATUS_UNDER_REVIEW, self::STATUS_CANCELLED],
33	        self::STATUS_UNDER_REVIEW => [self::STATUS_APPROVED, self::STATUS_REJECTED, self::STATUS_CANCELLED],
34	        self::STATUS_APPROVED => [self::STATUS_ENROLLED, self::STATUS_WAITLISTED, self::STATUS_CANCELLED],
35	        self::STATUS_REJECTED => [self::STATUS_DRAFT],
36	        self::STATUS_ENROLLED => [self::STATUS_CANCELLED, self::STATUS_COMPLETED],
37	        self::STATUS_WAITLISTED => [self::STATUS_ENROLLED, self::STATUS_CANCELLED],
38	        self::STATUS_CANCELLED => [self::STATUS_REFUNDED],
39	        self::STATUS_COMPLETED => [],
40	        self::STATUS_REFUNDED => [],
41	    ];
42	
43	    protected $fillable = [
