3	namespace App\Http\Controllers\Traits;
4	
5	use App\Models\Booking;
6	use App\Models\Enrollment;
7	use Illuminate\Database\Eloquent\Model;
8	use Illuminate\Http\Request;
9	use Symfony\Component\HttpKernel\Exception\AccessDeniedHttpException;
10	
11	/**
12	 * Provides object-level authorization helpers for controllers.
13	 *
14	 * Admin and planner roles have unrestricted access. Reviewer and field_agent
15	 * roles are scoped: they can only access records they created, are assigned to,
16	 * or are explicitly linked to via a verified ownership chain.
17	 */
18	trait AuthorizesRecordAccess
19	{
20	    /**
21	     * Ensure the authenticated user may access the given record.
22	     * Throws 403 if the user lacks sufficient scope.
23	     */
24	    protected function authorizeRecord(Request $request, Model $record): void
25	    {
26	        $user = $request->user();
27	
28	        if (!$user) {
29	            throw new AccessDeniedHttpException('Authentication required.');
30	        }
31	
32	        // Admin and planner have unrestricted object access
33	        if ($user->hasRole('admin') || $user->hasRole('planner')) {
34	            return;
35	        }
36	
37	        // Check ownership / assignment chains
38	        if ($this->userOwnsOrIsAssigned($user, $record)) {
39	            return;
40	        }
41	
42	        throw new AccessDeniedHttpException('You do not have access to this record.');
43	    }
44	
45	    /**
46	     * Determine if a user "owns" or is assigned to a record through any
47	     * recognised relationship chain.
48	     */
49	    private function userOwnsOrIsAssigned($user, Model $record): bool
50	    {
51	        // Direct user_id / created_by / booked_by ownership
52	        foreach (['user_id', 'created_by', 'booked_by', 'last_actor_id', 'reviewer_id', 'assigned_by'] as $col) {
53	            if (isset($record->{$col}) && (int) $record->{$col} === (int) $user->id) {
54	                return true;
55	            }
56	        }
57	
58	        // Learner-linked records: check if the user has a concrete operational
59	        // relationship with the learner (e.g. created a booking or enrollment
60	        // for that learner).
61	        if (isset($record->learner_id)) {
62	            return $this->userHasOperationalLinkToLearner($user, (int) $record->learner_id);
63	        }
64	
65	        return false;
66	    }
67	
68	    /**
69	     * Check if the user has a concrete operational link to a learner through
70	     * bookings or enrollments they created.
71	     */
72	    private function userHasOperationalLinkToLearner($user, int $learnerId): bool
73	    {
74	        // User booked something for this learner
75	        $hasBooking = Booking::where('learner_id', $learnerId)
76	            ->where('booked_by', $user->id)
77	            ->exists();
78	
79	        if ($hasBooking) {
80	            return true;
81	        }
82	
83	        // User was the last actor on an enrollment for this learner
84	        $hasEnrollment = Enrollment::where('learner_id', $learnerId)
85	            ->where('last_actor_id', $user->id)
86	            ->exists();
87	
88	        return $hasEnrollment;
89	    }
90	
91	    /**
92	     * Ensure the authenticated user may mutate (update/delete) the given record.
93	     * More restrictive than read access.
94	     */
95	    protected function authorizeMutation(Request $request, Model $record): void
96	    {
97	        $user = $request->user();
98	
99	        if (!$user) {
100	            throw new AccessDeniedHttpException('Authentication required.');
101	        }
102	
103	        if ($user->hasRole('admin') || $user->hasRole('planner')) {
104	            return;
105	        }
106	
107	        // Only the creator/owner can mutate
108	        foreach (['user_id', 'created_by', 'booked_by', 'last_actor_id', 'assigned_by'] as $col) {
109	            if (isset($record->{$col}) && (int) $record->{$col} === (int) $user->id) {
110	                return;
111	            }
112	        }
113	
114	        throw new AccessDeniedHttpException('You do not have permission to modify this record.');
115	    }
116	}
