17	
18	class WaitlistLifecycleApiTest extends TestCase
19	{
20	    use RefreshDatabase;
21	
22	    private string $token;
23	    private User $user;
24	    private Learner $learner;
25	    private Learner $learner2;
26	    private Resource $resource;
27	
28	    protected function setUp(): void
29	    {
30	        parent::setUp();
31	
32	        $role = Role::create(['name' => 'Administrator', 'slug' => 'admin']);
33	        $perms = ['bookings.create', 'bookings.view', 'bookings.update', 'bookings.cancel'];
34	        foreach ($perms as $p) {
35	            $perm = Permission::create(['name' => $p, 'slug' => $p]);
36	            $role->permissions()->attach($perm);
37	        }
38	
39	        $this->user = User::create([
40	            'username' => 'admin', 'name' => 'Admin', 'email' => 'admin@test.com',
41	            'password' => Hash::make('Pass1234!@'), 'role_id' => $role->id, 'is_active' => true,
42	        ]);
43	
44	        $this->token = 'wait-token-padded-to-exactly-sixty-four-characters-long-here-ok!';
45	        ApiToken::create([
46	            'user_id' => $this->user->id,
47	            'token' => hash('sha256', $this->token),
48	            'expires_at' => now()->addHours(24),
49	        ]);
50	
51	        $this->learner = Learner::create(['first_name' => 'Jane', 'last_name' => 'Doe']);
52	        $this->learner2 = Learner::create(['first_name' => 'Bob', 'last_name' => 'Smith']);
53	        $this->resource = Resource::create(['name' => 'Room A', 'type' => 'room', 'capacity' => 1]);
54	    }
55	
56	    private function auth(): array
57	    {
58	        return ['Authorization' => "Bearer {$this->token}"];
59	    }
60	
61	    public function test_waitlist_entry_gets_offered_after_cancellation(): void
62	    {
63	        $startTime = now()->addDays(2)->startOfHour();
64	        $endTime = $startTime->copy()->addMinutes(30);
65	
66	        // Book the resource (fills capacity = 1)
67	        $booking = Booking::create([
68	            'resource_id' => $this->resource->id,
69	            'learner_id' => $this->learner->id,
70	            'booked_by' => $this->user->id,
71	            'status' => Booking::STATUS_CONFIRMED,
72	            'start_time' => $startTime,
73	            'end_time' => $endTime,
74	            'version' => 1,
75	            'confirmed_at' => now(),
76	        ]);
77	
78	        // Add learner2 to waitlist
79	        $response = $this->withHeaders($this->auth())
80	            ->postJson('/api/waitlist', [
81	                'resource_id' => $this->resource->id,
82	                'learner_id' => $this->learner2->id,
83	                'start_time' => $startTime->toIso8601String(),
84	                'end_time' => $endTime->toIso8601String(),
85	            ]);
86	
87	        $response->assertStatus(201);
88	        $entryId = $response->json('data.id');
89	
90	        // Cancel the booking — should trigger waitlist offer
91	        $cancelResponse = $this->withHeaders($this->auth())
92	            ->postJson("/api/bookings/{$booking->id}/cancel");
93	
94	        $cancelResponse->assertStatus(200);
95	
96	        // Verify the waitlist entry was offered
97	        $entry = WaitlistEntry::find($entryId);
98	        $this->assertEquals(WaitlistEntry::STATUS_OFFERED, $entry->status);
99	        $this->assertNotNull($entry->offered_at);
100	        $this->assertNotNull($entry->offer_expires_at);
101	    }
102	
103	    public function test_expired_waitlist_offer_cannot_be_accepted(): void
104	    {
105	        $startTime = now()->addDays(2)->startOfHour();
106	        $endTime = $startTime->copy()->addMinutes(30);
107	
108	        // Create an already-expired waitlist offer
109	        $entry = WaitlistEntry::create([
110	            'resource_id' => $this->resource->id,
111	            'learner_id' => $this->learner->id,
112	            'desired_start_time' => $startTime,
113	            'desired_end_time' => $endTime,
114	            'status' => WaitlistEntry::STATUS_OFFERED,
115	            'offered_at' => now()->subMinutes(15),
116	            'offer_expires_at' => now()->subMinutes(5),
117	            'position' => 1,
118	        ]);
119	
120	        $response = $this->withHeaders($this->auth())
121	            ->postJson("/api/waitlist/{$entry->id}/accept");
122	
123	        $response->assertStatus(422)
124	            ->assertJsonFragment(['error' => 'Waitlist Error']);
125	    }
126	
127	    public function test_accept_valid_waitlist_offer_creates_booking(): void
